#include <bits/stdc++.h>
#define ull unsigned long long
#define mk(x,y) make_pair(x,y)
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb(x) push_back(x)
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh(x) while(x)
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
using NP std;
il ll read()
{
    ll x=0,f=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=getchar();}
    return x*f;
}
void write(ll x)
{
    if(x<0)putchar('-'),x=-x;
    if(x>9)write(x/10);
    putchar(x%10+'0');
}
void writeln(ll x)
{
    write(x);
    puts("");
    return;
}
CI MAXN=1e6+5;
PII a[MAXN];
int v[MAXN],n,s,l=1,r=1,num=0,ans=inf,cnt=0;
int main(void){
	n=read(),s=read();
	FOR(i,1,n)
    {
        FOR(j,1,s)
        {
			int x=read();
			a[++cnt]=mk(x,i);
		}
    }
	sort(a+1,a+cnt+1);
	wh(r<=cnt)
    {
		if(!v[a[r].snd])++num;
        ++v[a[r].snd];
        if(num==n)
        {
			wh(v[a[l].snd]>=2)--v[a[l++].snd]; 
			ans=min(ans,a[r].fst-a[l].fst);
		}
        ++r;
	}
    writeln(ans);
	return false;
}
